function load_settings()
    if not doesDirectoryExist(configDirectory) then createDirectory(configDirectory) end
    if not doesFileExist(configDirectory .. "/Settings.json") then
        settings = default_settings
		print('รร รฉรซ รฑ รญร รฑรฒรฐรฎรฉรชร รฌรจ รญรฅ รญร รฉรครฅรญ, รจรฑรฏรฎรซรผรงรณรพ รฑรฒร รญรคร รฐรฒรญรปรฅ รญร รฑรฒรฐรฎรฉรชรจ!')
    else
        local file = io.open(configDirectory .. "/Settings.json", 'r')
        if file then
            local contents = file:read('*a')
            file:close()
			if #contents ~= 0 then
				local result, loaded = pcall(decodeJson, contents)
				if result then	
					settings = loaded
					if settings.general.version ~= thisScript().version then
						print('รรฎรขร รฟ รขรฅรฐรฑรจรฟ, รฑรกรฐรฎรฑ รญร รฑรฒรฐรฎรฅรช!')
						local fraction_mode = settings.general.fraction_mode
						local player_info = settings.player_info
						local key = settings.general.key
						settings = default_settings
						settings.player_info = player_info
						settings.general.fraction_mode = fraction_mode
						settings.general.key = key or ''
						save_settings()
						reload_script = true
						thisScript():reload()
					else
						print('รร รฑรฒรฐรฎรฉรชรจ รณรฑรฏรฅรธรญรฎ รงร รฃรฐรณรฆรฅรญรป!')
					end
				else
					settings = default_settings
					print('รรฅ รณรคร รซรฎรฑรผ รฎรฒรชรฐรปรฒรผ รดร รฉรซ รฑ รญร รฑรฒรฐรฎรฉรชร รฌรจ, รจรฑรฏรฎรซรผรงรณรพ รฑรฒร รญรคร รฐรฒรญรปรฅ รญร รฑรฒรฐรฎรฉรชรจ!')
				end
			else
                settings = default_settings
				print('รรฅ รณรคร รซรฎรฑรผ รฎรฒรชรฐรปรฒรผ รดร รฉรซ รฑ รญร รฑรฒรฐรฎรฉรชร รฌรจ, รจรฑรฏรฎรซรผรงรณรพ รฑรฒร รญรคร รฐรฒรญรปรฅ รญร รฑรฒรฐรฎรฉรชรจ!')
			end
        else
            settings = default_settings
			print('รรฅ รณรคร รซรฎรฑรผ รฎรฒรชรฐรปรฒรผ รดร รฉรซ รฑ รญร รฑรฒรฐรฎรฉรชร รฌรจ, รจรฑรฏรฎรซรผรงรณรพ รฑรฒร รญรคร รฐรฒรญรปรฅ รญร รฑรฒรฐรฎรฉรชรจ!')
        end
    end
