function save_settings()
    local file, errstr = io.open(configDirectory .. "/Settings.json", 'w')
    if file then
		local function looklike(array) 
			local dkok, dkjson = pcall(require, "dkjson") 
			if dkok then 
				local ok, encoded = pcall(dkjson.encode, array, {indent = true})
				if ok then return encoded end
			else
				local ok, encoded = pcall(encodeJson, array) 
				if ok then return encoded end 
			end
		end
		local content = looklike(settings)
		if content then
			file:write(content)
			print('รร รฑรฒรฐรฎรฉรชรจ รตรฅรซรฏรฅรฐร  รฑรฎรตรฐร รญรฅรญรป!')
		else
			print('รรฅ รณรคร รซรฎรฑรผ รฑรฎรตรฐร รญรจรฒรผ รญร รฑรฒรฐรฎรฉรชรจ รตรฅรซรฏรฅรฐร ! รรธรจรกรชร  รชรฎรครจรฐรฎรขรชรจ json')
		end
		file:close()
    else
        print('รรฅ รณรคร รซรฎรฑรผ รฑรฎรตรฐร รญรจรฒรผ รญร รฑรฒรฐรฎรฉรชรจ รตรฅรซรฏรฅรฐร , รฎรธรจรกรชร : ', errstr)
    end
end
