function load_module(key)
    local obj = modules[key]
	if not obj then
		print('รรธรจรกรชร : รญรฅรจรงรขรฅรฑรฒรญรปรฉ รฌรฎรครณรซรผ "' .. key .. '"!')
	else
		if doesFileExist(obj.path) then
			local file, errstr = io.open(obj.path, 'r')
			if file then
				local contents = file:read('*a')
				file:close()
				if #contents == 0 then
					print('รรฅ รณรคร รซรฎรฑรผ รฎรฒรชรฐรปรฒรผ รฌรฎรครณรซรผ "' .. obj.name .. '". รรฐรจรทรจรญร : รดร รฉรซ รฏรณรฑรฒรฎรฉ')
				else
					local result, loaded = pcall(decodeJson, contents)
					if result then
						obj.data = loaded
						print('รรฎรครณรซรผ "' .. obj.name .. '" รจรญรจรถรจร รซรจรงรจรฐรฎรขร รญ! (รฅรฑรฒรผ รขร รธรจ รชร รฑรฒรฎรฌรญรปรฅ รคร รญรญรปรฅ)')
					else
						print('รรฅ รณรคร รซรฎรฑรผ รฎรฒรชรฐรปรฒรผ รฌรฎรครณรซรผ "' .. obj.name .. '". รรธรจรกรชร : decode json')
					end
				end
			else
				print('รรฅ รณรคร รซรฎรฑรผ รฎรฒรชรฐรปรฒรผ รฌรฎรครณรซรผ "' .. obj.name .. '". รรธรจรกรชร : ' .. tostring(errstr or "รญรฅรจรงรขรฅรฑรฒรญร รฟ"))
			end
		else
			print('รรฎรครณรซรผ "' .. obj.name .. '" รจรญรจรถรจร รซรจรงรจรฐรฎรขร รญ!')
		end
	end
end
function save_module(key)
    local obj = modules[key]
	if not obj then
		print('รรธรจรกรชร : รญรฅรจรงรขรฅรฑรฒรญรปรฉ รฌรฎรครณรซรผ "' .. key .. '"!')
	else
		local file, errstr = io.open(obj.path, 'w')
		if file then
			local function looklike(array)
				local dkok, dkjson = pcall(require, "dkjson")
				if dkok then
					local ok, encoded = pcall(dkjson.encode, array, {indent = true})
					if ok then return encoded end
				else
					local ok, encoded = pcall(encodeJson, array)
					if ok then return encoded end
				end
			end
			local content = looklike(obj.data)
			if content then
				file:write(content)
				print('รรฎรครณรซรผ "' .. obj.name .. '" รฑรฎรตรฐร รญยธรญ!')
			else
				print('รรฅ รณรคร รซรฎรฑรผ รฑรฎรตรฐร รญรจรฒรผ รฌรฎรครณรซรผ "' .. obj.name .. '" - รฎรธรจรกรชร  รชรฎรครจรฐรฎรขรชรจ json!')
			end
			file:close()
		else
			print('รรฅ รณรคร รซรฎรฑรผ รฑรฎรตรฐร รญรจรฒรผ รฌรฎรครณรซรผ "' .. obj.name .. '", รฎรธรจรกรชร : ' .. tostring(errstr or "รญรฅรจรงรขรฅรฑรฒรญร รฟ"))
		end
	end
end
