				for i, plate in pairs(modules.arz_veh.cache) do
					result, veh = sampGetCarHandleBySampVehicleId(plate.carID)
					if result and veh == car then
						return ' c รญรฎรฌรฅรฐร รฌรจ ' .. plate.number
					end
				end
				return ''
