	get_patrool_format_time = function()
		local hours = math.floor(MODULE.Patrool.time / 3600)
		local minutes = math.floor((MODULE.Patrool.time % 3600) / 60)
		local secs = MODULE.Patrool.time % 60
		if hours > 0 then
			return string.format("%d รทร รฑรฎรข %d รฌรจรญรณรฒ %d รฑรฅรชรณรญรค", hours, minutes, secs)
		elseif minutes > 0 then
			return string.format("%d รฌรจรญรณรฒ %d รฑรฅรชรณรญรค", minutes, secs)
		else
			return string.format("%d รฑรฅรชรณรญรค(-รป)", secs)
		end
	end,
