	if isMonetLoader() then
		local function downloadToFile(url, path)
			local http = require("socket.http")
			local ltn12 = require("ltn12")

			local f, ferr = io.open(path, "wb")
			if not f then
				return false, "รรฅ รณรคร รซรฎรฑรผ รฑรฎรงรคร รฒรผ รดร รฉรซ: " .. tostring(ferr)
			end

			local ok, code, headers, status = http.request{
				method = "GET",
				url = url,
				sink = ltn12.sink.file(f)
			}

			if not ok then
				return false, "รรธรจรกรชร  รงร รฏรฐรฎรฑร : " .. tostring(code)
			end

			if tonumber(code) ~= 200 then
				return false, "HTTP รชรฎรค: " .. tostring(code)
			end

			return true
		end
		local ok, err = downloadToFile(url, path)
		if ok then
			on_finish_download()
		else
			sampAddChatMessage("[Arizona Helper] {ffffff}รรธรจรกรชร  รงร รฃรฐรณรงรชรจ รดร รฉรซร : " .. tostring(err), message_color)
		end
	else
		downloadUrlToFile(url, path, function(id, status)
			if status == 6 then
				on_finish_download()
			end
		end)
	end
end
