function sampev.onSendChat(text)
	if (MODULE.DEBUG) then
		sampAddChatMessage('[SendChat] {ffffff}Text ' .. text, message_color)
		print('[SendChat] ' .. text)
	end
	local ignore = {
		[")"] = true,
		["))"] = true,
		["("] = true,
		["(("] = true,
		["q"] = true,
		["<3"] = true,
	}
	if ignore[text] then
		return {text}
	end
	if settings.player_info.rp_chat then
		text = text:sub(1, 1):rupper()..text:sub(2, #text) 
		if not text:find('(.+)%.') and not text:find('(.+)%!') and not text:find('(.+)%?') then
			text = text .. '.'
		end
	end
	if settings.player_info.accent_enable then
		text = settings.player_info.accent .. ' ' .. text 
	end
	return {text}
end
function sampev.onSendCommand(text)
	if (MODULE.DEBUG) then
		sampAddChatMessage('[SendCommand] {ffffff}CMD ' .. text, message_color)
		print('[SendCommand] CMD ' .. text)
	end
	if isMode('hospital') and text == "/me รครฎรฑรฒร ยธรฒ รจรง รฑรขรฎรฅรฃรฎ รฌรฅรค.รชรฅรฉรฑร  รซรฅรชร รฐรฑรฒรขรฎ รจ รฏรฐรจรญรจรฌร รฅรฒ รฅรฃรฎ" then
		MODULE.HealChat.healme = true
	end
	if settings.player_info.rp_chat then
		local chats =  { '/vr', '/fam', '/al', '/s', '/b', '/n', '/r', '/rb', '/f', '/fb', '/j', '/jb', '/m', '/do'} 
		for _, cmd in ipairs(chats) do
			if text:find('^'.. cmd .. ' ') then
				local cmd_text = text:match('^'.. cmd .. ' (.+)')
				if cmd_text ~= nil then
					cmd_text = cmd_text:sub(1, 1):rupper()..cmd_text:sub(2, #cmd_text)
					text = cmd .. ' ' .. cmd_text
					if not text:find('(.+)%.') and not text:find('(.+)%!') and not text:find('(.+)%?') then
						text = text .. '.'
					end
				end
			end
		end
	end
	return {text}
end
function sampev.onShowDialog(dialogid, style, title, button1, button2, text)
	if (MODULE.DEBUG) then
		sampAddChatMessage('[ShowDialog] {ffffff}ID ' .. dialogid .. ' | Style ' .. style .. ' | Title ' .. title .. ' | Btn1 ' .. button1 .. ' | Btn2 ' .. button2 .. ' | Text ' .. text, message_color)
		print('[ShowDialog] ID ' .. dialogid .. ' | Style ' .. style .. ' | Title ' .. title .. ' | Btn1 ' .. button1 .. ' | Btn2 ' .. button2 .. ' | Text ' .. text)
	end

	if ((check_stats) and (title:find('รรฑรญรฎรขรญร รฟ รฑรฒร รฒรจรฑรฒรจรชร ') or title:find('รรฒร รฒรจรฑรฒรจรชร  รจรฃรฐรฎรชร '))) then
		-- Arizona & Rodina Stats
		if text:find("รรฌรฟ") then
			settings.player_info.nick = text:match("{FFFFFF}รรฌรฟ: {B83434}%[(.-)]") or text:match("{ffffff}รรฌรฟ %(en%.%):%s+{BE433D}([^\n\r]+)")
			settings.player_info.name_surname = text:match("{ffffff}รรฌรฟ %(รฐรณรฑ%.%):%s+{BE433D}([^\n\r]+)") or TranslateNick(settings.player_info.nick)
			sampAddChatMessage('[Arizona Helper] {ffffff}รร รธรฅ รจรฌรฟ รจ รดร รฌรจรซรจรฟ รฎรกรญร รฐรณรฆรฅรญรป: ' .. settings.player_info.name_surname, message_color)
        end
		if text:find("รรฎรซ:") then
			settings.player_info.sex = text:match("{FFFFFF}รรฎรซ: {B83434}%[(.-)]") or text:match("{ffffff}รรฎรซ:%s+{BE433D}([^\n\r]+)")
			sampAddChatMessage('[Arizona Helper] {ffffff}รร รธ รฏรฎรซ รฎรกรญร รฐรณรฆรฅรญ: ' .. settings.player_info.sex, message_color)
		end
		if text:find("รรฐรฃร รญรจรงร รถรจรฟ:") then
